  // Collect which values go to which destination.
  // ucmp/scmp can only return -1, 0, or 1.
  bool HasMinusOne = false, HasZero = false, HasOne = false;
  BasicBlock *MinusOneDest = nullptr, *ZeroDest = nullptr, *OneDest = nullptr;

  for (const auto &Case : SI->cases()) {
    const APInt &Val = Case.getCaseValue()->getValue();
    BasicBlock *Dest = Case.getCaseSuccessor();
    if (Val == -1) {
      HasMinusOne = true;
      MinusOneDest = Dest;
    } else if (Val == 0) {
      HasZero = true;
      ZeroDest = Dest;
    } else if (Val == 1) {
      HasOne = true;
      OneDest = Dest;
    } else {
      return false; // Unexpected value for ucmp/scmp result.
    }
  }

