  if (!HasMinusOne)
    MinusOneDest = DefaultDest;
  if (!HasZero)
    ZeroDest = DefaultDest;
  if (!HasOne)
    OneDest = DefaultDest;

  // We need exactly two destinations, so exactly one of the three values
  // must go to a different destination than the other two.
  ICmpInst::Predicate Pred;
  BasicBlock *TrueDest, *FalseDest;

  if (MinusOneDest == ZeroDest && ZeroDest != OneDest) {
    // -1 and 0 go to same dest, 1 goes to other: check if LHS <= RHS (or LHS > RHS for the other)
    // This is equivalent to checking if LHS > RHS for the "1" case.
    TrueDest = OneDest;
    FalseDest = MinusOneDest;
    Pred = CI->getGTPredicate();
