    // -1 and 1 go to same dest, 0 goes to other: check if LHS != RHS
    TrueDest = ZeroDest;
    FalseDest = MinusOneDest;
    Pred = ICmpInst::ICMP_EQ;
  } else if (ZeroDest == OneDest && OneDest != MinusOneDest) {
    // 0 and 1 go to same dest, -1 goes to other: check if LHS >= RHS (or LHS < RHS for the other)
    // This is equivalent to checking if LHS < RHS for the "-1" case.
