    unsigned NumEdges = 0;
    for (unsigned I = 0, E = SI->getNumSuccessors(); I != E; ++I)
      if (SI->getSuccessor(I) == FalseDest)
        ++NumEdges;
    for (unsigned I = 0, E = NumEdges - 1; I != E; ++I)
