  // Clean up the default block if it was unreachable.
  if (isa<UnreachableInst>(DefaultDest->getFirstNonPHIOrDbg()))
    createUnreachableSwitchDefault(SI, DTU);

  // Erase the switch.
  SI->eraseFromParent();

  return true;
